```javascript
const { Client, Collection, Intents } = require('discord.js');

const client = new Client();

const commands = {
  ban: {
    name: 'ban',
    description: 'Bans a user from the server.',
    usage: '<user | @user>',
    options: [
      {
        name:'reason',
        description: 'The reason for the ban.',
        optionality: 'optional'
      }
    ],
    guildOnly: true,
    permission: 'BAN_MEMBERS'
  }
};

client.commands = new Collection();

for (const command of commands) {
  client.commands.set(command.name, command);
}

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('messageCreate', async message => {
  if (!message.content.startsWith('!')) return;

  const args = message.content.slice(1).split(/ +/);
  const commandName = args.shift().toLowerCase();

  const command = client.commands.get(commandName);

  if (!command) return;

  const { options } = command;

  const user = message.mentions.users.first();

  const userId = user?.id;
  const userName = user?.tag;

  const filteredArgs = options.filter(option => option.optionality === 'optional' && args.includes(option.name));

  const reason = filteredArgs.length > 0? args.join(' ') : null;

  const context = message.channel.send(`${userName} has been banned from the server by ${client.user.tag} with reason: ${reason}`);

  if (command.guildOnly) {
    context.delete();
  }
});

client.on('error', console.error);

